parameters.text:
=🚨 *HR Alert: Document Ingestion Failed* 🚨

The AI database could not read an uploaded document.

*File:* {{$json.failed_file}}

*Issue:* {{$json.reason}}

Please check the file in the shared directory.

parameters.jsCode:
const item = $input.all()[0];

let fileName = "Unknown File";
let errorMessage = "Unknown Error";
let errorType = "FILE_ERROR"; // Default to Dev Team
let nodeName = "Unknown Node";
let filePath = "Path not available"; // <--- ADDED THIS

// Scenario 1: Native n8n Node Error (Code/Pipeline crashed)
if (item.json.error && typeof item.json.error === 'object' && item.json.error.message) {
    errorMessage = item.json.error.message;
    errorType = "SYSTEM_ERROR"; 

    // n8n often embeds the node name in the error object
    if (item.json.error.node && item.json.error.node.name) {
        nodeName = item.json.error.node.name;
    }

    // Try to salvage filename and path
    if (item.binary && item.binary.data && item.binary.data.fileName) {
        fileName = item.binary.data.fileName;
    } else if (item.json.fileName) {
        fileName = item.json.fileName;
    }

    // <--- ADDED THIS TO CATCH PATH --->
    if (item.json.path) filePath = item.json.path;

} 
// Scenario 2: Custom Pipeline Error (File is corrupt/unreadable)
else if (item.json.error && typeof item.json.error === 'string') {
    errorMessage = item.json.error;
    errorType = "FILE_ERROR";
    fileName = item.json.fileName || "Unknown File";
    filePath = item.json.path || "Path not available"; // <--- ADDED THIS
    nodeName = "HASH GENERATOR (Read Error)";
}

return {
    json: {
        error_type: errorType,
        failed_file: fileName,
        file_path: filePath, // <--- ADDED THIS TO THE OUTPUT
        reason: errorMessage,
        node_name: nodeName,
        timestamp: new Date().toISOString()
    }
};
